def generar_contrato(brief_cliente):
    requisitos = pedir_a_claude(f"Extraé los requisitos clave de: {brief_cliente}")

    if "falta" in requisitos.lower():  # gate
        return {"error": "requisitos incompletos, pedir más info al cliente"}

    borrador = pedir_a_claude(f"Redactá un borrador con estos requisitos: {requisitos}")
    version_final = pedir_a_claude(f"Revisá y pulí el lenguaje legal de: {borrador}")
    return {"contrato": version_final}

PROMPTS_POR_CATEGORIA = {
    "tecnico": ("claude-opus-4-8", "Sos soporte técnico nivel 2..."),
    "facturacion": ("claude-sonnet-4-6", "Sos soporte de facturación..."),
    "faq": ("claude-haiku-4-5-20251001", "Respondé preguntas frecuentes brevemente..."),
}

def enrutar_y_responder(mensaje):
    # modelo barato para clasificar
    categoria = pedir_a_claude(
        f"Clasificá en tecnico/facturacion/faq (una palabra): {mensaje}",
        modelo="claude-haiku-4-5-20251001",
    ).strip()

    modelo, system_prompt = PROMPTS_POR_CATEGORIA.get(categoria, PROMPTS_POR_CATEGORIA["faq"])
    return pedir_a_claude(mensaje, modelo=modelo, system=system_prompt)

def generar_con_evaluacion(tarea, criterios, max_intentos=3):
    feedback = ""
    for intento in range(max_intentos):
        borrador = pedir_a_claude(f"{tarea}\n\nFeedback de la iteración anterior: {feedback}")
        evaluacion = pedir_a_claude(
            f"Evaluá si este texto cumple estos criterios: {criterios}\n\nTexto: {borrador}\n\n"
            "Si cumple todo, respondé exactamente 'OK'. Si no, devolvé feedback específico y accionable."
        )
        if evaluacion.strip() == "OK":
            return borrador
        feedback = evaluacion
    return borrador  # se devuelve el último intento aunque no haya aprobado

