def agente(objetivo, tools, max_iteraciones=8):
    mensajes = [{"role": "user", "content": objetivo}]

    for i in range(max_iteraciones):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=1500, tools=tools, messages=mensajes
        )
        mensajes.append({"role": "assistant", "content": response.content})

        if response.stop_reason != "tool_use":
            return response  # el agente considera la tarea terminada

        resultados = ejecutar_y_recolectar_tools(response.content)
        mensajes.append({"role": "user", "content": resultados})

    raise RuntimeError("el agente no convergió dentro del límite de iteraciones")

def compactar_si_hace_falta(mensajes, umbral_tokens=50000, conservar_ultimos=4):
    if estimar_tokens(mensajes) < umbral_tokens:
        return mensajes

    historial_viejo = mensajes[:-conservar_ultimos]
    resumen = pedir_a_claude(
        f"Resumí en pocos párrafos lo relevante de esto para continuar la tarea:\n{historial_viejo}"
    )
    return [
        {"role": "user", "content": f"Resumen de lo actuado hasta ahora:\n{resumen}"}
    ] + mensajes[-conservar_ultimos:]

